            'description'      : 'Log-transform right-skewed income'
        },
        'amount': {
            'detection_method' : 'iqr',
            'treat_method'     : 'cap',
            'iqr_multiplier'   : 1.5,
            'description'      : 'Cap Tukey fences for loan amount'
        },
        'rate': {
            'detection_method' : 'iqr',
            'treat_method'     : 'retain',
            'iqr_multiplier'   : 1.5,
            'description'      : 'High rates are legitimate; retain all values'
        },
    }
}

def compute_iqr_fences(series, multiplier=1.5):
    q1, q3 = series.quantile(0.25), series.quantile(0.75)
    iqr = q3 - q1
    return q1 - multiplier * iqr, q3 + multiplier * iqr

def handle_outliers(df, config=None):
    if config is None: config = OUTLIER_CONFIG
    df_c = df.copy()
    audit = {'rows_input': len(df), 'rows_removed': 0, 'details': {}}

    for feat, cfg in config['features'].items():
        if feat not in df_c.columns: continue
        treat = cfg['treat_method']
        detail = {'treat_method': treat, 'rows_removed': 0}

        if treat == 'remove':
            before = len(df_c)
            if 'lower_bound' in cfg:
                df_c = df_c[pd.to_numeric(df_c[feat], errors='coerce') >= cfg['lower_bound']]
            if 'upper_bound' in cfg:
                df_c = df_c[pd.to_numeric(df_c[feat], errors='coerce') <= cfg['upper_bound']]
            removed = before - len(df_c)
            audit['rows_removed'] += removed
            detail['rows_removed'] = removed
            logger.info(f'✓ {feat}: removed {removed} rows (domain bounds)')

        elif treat == 'cap':
            lower_f, upper_f = compute_iqr_fences(df_c[feat].dropna(), cfg.get('iqr_multiplier', 1.5))
            df_c[feat] = df_c[feat].clip(lower=lower_f, upper=upper_f)
            logger.info(f'✓ {feat}: capped to [{lower_f:.2f}, {upper_f:.2f}]')

        elif treat == 'transform':
            t = cfg.get('transform_type', 'log1p')
            new_col = f'{feat}_log'
            if t == 'log1p':
                df_c[new_col] = np.log1p(df_c[feat])
            elif t == 'sqrt':
                df_c[new_col] = np.sqrt(df_c[feat])
            logger.info(f'✓ {feat}: {t} → {new_col}')

        elif treat == 'retain':
            if cfg.get('detection_method') == 'iqr':
                lf, uf = compute_iqr_fences(df_c[feat].dropna(), cfg.get('iqr_multiplier', 1.5))
                n_out = ((df_c[feat] < lf) | (df_c[feat] > uf)).sum()
                logger.info(f'✓ {feat}: {n_out} IQR outliers detected but retained')

        audit['details'][feat] = detail

    audit['rows_output'] = len(df_c)
    return df_c, audit

df_clean, out_audit = handle_outliers(df_clean, OUTLIER_CONFIG)
print(f'Rows: {out_audit["rows_input"]} → {out_audit["rows_output"]}  (removed: {out_audit["rows_removed"]})')

